213→export const uploadJournalContentService = async(
214→    content,
215→    title,
216→    userId,
217→    postType = POST_TYPE_TEXT,
218→    canvasDocInput = null,
219→    remixSourceJournalId = null,
220→    isRemix = false
221→) =>{
222→    if(!userId){
223→        console.error('userId is undefined');
224→        throw {status: 400, error: 'userId is undefined'};
225→    }
226→
227→    const resolvedPostType = normalizePostType(postType);
228→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
229→
230→    if(!trimmedTitle){
231→        console.error('title is missing!');
232→        throw {status: 400, error: 'title is missing!'};
233→    }
234→
235→    let embeddingBody = '';
236→    const shouldSaveRemixMetadata = Boolean(
237→        remixSourceJournalId
238→        && typeof remixSourceJournalId === 'string'
239→        && remixSourceJournalId.trim()
240→    );
241→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
242→    let payload = {
243→        user_id: userId,
244→        title: trimmedTitle,
245→        post_type: resolvedPostType
246→    };
247→
248→    if(resolvedPostType === POST_TYPE_CANVAS){
249→        let parsedCanvasDoc = null;
250→        try {
251→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
252→        } catch (error) {
253→            console.error('invalid canvas doc on insert:', error?.message || error);
254→            throw {status: 400, error: 'invalid canvas_doc'};
255→        }
256→
257→        if(!parsedCanvasDoc){
258→            console.error('canvas_doc is missing for canvas post');
259→            throw {status: 400, error: 'canvas_doc is missing'};
260→        }
261→
262→        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
263→        payload = {
264→            ...payload,
265→            content: null,
266→            canvas_doc: parsedCanvasDoc
267→        };
268→    } else {
269→        if(!content){
270→            console.error('content is missing for text post!');
271→            throw {status: 400, error: 'content is missing for text post'};
272→        }
273→
274→        const parseData = parseTextContentSafely(content);
275→        if(!parseData){
276→            console.error('error while parsing text content data');
277→            throw {status: 400, error: 'error while parsing text content data'};
278→        }
279→
280→        embeddingBody = parseData.wholeText || '';
281→        payload = {
282→            ...payload,
283→            content: content,
284→            canvas_doc: null
285→        };
286→    }
287→
288→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
289→
290→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
291→        console.error('error while generating embeddings on a post!');
292→        throw {status: 400, error: 'error while generating embeddings on a post!'};
293→    }
294→
295→    const insertPayload = {
296→        ...payload,
297→        embeddings: embeddingResult
298→    };
299→
300→    if(normalizedIsRemix){
301→        insertPayload.is_remix = true;
302→    }
303→    if(shouldSaveRemixMetadata){
304→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
305→    }
306→
307→    try {
308→        const {count: postCount} = await supabase
309→            .from('journals')
310→            .select('id', {count: 'exact', head: true})
311→            .eq('user_id', userId);
312→        const home = userHomeCoords(userId);
313→        const offset = spiralLayout(postCount || 0);
314→        insertPayload.universe_x = home.x + offset.dx;
315→        insertPayload.universe_y = home.y + offset.dy;
316→    } catch (coordErr) {
317→        console.error('non-fatal: failed to compute universe coords:', coordErr?.message || coordErr);
318→    }
319→
320→    let {error} = await supabase
321→    .from('journals')
322→    .insert(insertPayload);
323→
324→    if(error){
325→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
326→        if(missingRemixColumns){
327→            const fallbackPayload = {
328→                ...payload,
329→                embeddings: embeddingResult
330→            };
331→
332→            const retry = await supabase
333→            .from('journals')
334→            .insert(fallbackPayload);
335→            error = retry.error;
336→        }
337→    }
338→
339→    if(error){
340→        console.error('supabase error while uploading content:',error.message);
341→        throw {status: 500, error: 'supabase error while uploading content'};
342→    }
343→    return true;
344→}
